import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import styled from '@emotion/styled';
import Icon, { Size } from './index';

const meta = {
  component: Icon,
  title: 'Components/Icon',
} satisfies Meta<typeof Icon>;

export default meta;
type Story = StoryObj<typeof meta>;

const IconGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(120px, 1fr));
  gap: 16px;
  padding: 16px;
`;

const IconCell = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  padding: 8px;
  border: 1px solid #e5e5e5;
  border-radius: 4px;
  font-size: 12px;
  text-align: center;
`;

export const DefaultSize: Story = {
  render: () => (
    <IconGrid>
      <IconCell>
        <Icon glyph="ChevronRight" />
        <span>ChevronRight</span>
      </IconCell>
      <IconCell>
        <Icon glyph="ChevronLeft" />
        <span>ChevronLeft</span>
      </IconCell>
      <IconCell>
        <Icon glyph="CaretUp" />
        <span>CaretUp</span>
      </IconCell>
      <IconCell>
        <Icon glyph="CaretDown" />
        <span>CaretDown</span>
      </IconCell>
      <IconCell>
        <Icon glyph="CaretRight" />
        <span>CaretRight</span>
      </IconCell>
    </IconGrid>
  ),
  play: async ({ canvas }) => {
    const icons = canvas.getAllByRole('img');
    await expect(icons.length).toBeGreaterThanOrEqual(5);
  },
};

export const SmallSize: Story = {
  render: () => (
    <IconGrid>
      <IconCell>
        <Icon glyph="ChevronRight" size="small" />
        <span>ChevronRight</span>
      </IconCell>
      <IconCell>
        <Icon glyph="Plus" size="small" />
        <span>Plus</span>
      </IconCell>
      <IconCell>
        <Icon glyph="X" size="small" />
        <span>X</span>
      </IconCell>
      <IconCell>
        <Icon glyph="Filter" size="small" />
        <span>Filter</span>
      </IconCell>
    </IconGrid>
  ),
  play: async ({ canvas }) => {
    const icons = canvas.getAllByRole('img');
    await expect(icons.length).toBeGreaterThanOrEqual(4);
  },
};

export const LargeSize: Story = {
  render: () => (
    <IconGrid>
      <IconCell style={{ gridColumn: '1 / 2' }}>
        <Icon glyph="ChevronRight" size="large" />
        <span>ChevronRight</span>
      </IconCell>
      <IconCell style={{ gridColumn: '2 / 3' }}>
        <Icon glyph="ArrowUp" size="large" />
        <span>ArrowUp</span>
