export const Closed: Story = {
  render: () => (
    <Accordion title="Click to expand">
      <ContentContainer>
        <p>This is the expanded content that appears when you click the accordion header.</p>
      </ContentContainer>
    </Accordion>
  ),
  play: async ({ canvas, userEvent }) => {
    const toggle = canvas.getByRole('button', { name: /click to expand/i });
    await expect(toggle).toBeVisible();

    // Content should be hidden
    const content = canvas.getByText(/this is the expanded content/i);
    const accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'false');
  },
};

export const Open: Story = {
  render: () => (
    <Accordion title="Click to collapse" defaultOpen={true}>
      <ContentContainer>
        <p>This content is displayed by default when the accordion is open.</p>
      </ContentContainer>
    </Accordion>
  ),
  play: async ({ canvas }) => {
    // Content should be visible
    const content = canvas.getByText(/this content is displayed by default/i);
    const accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'true');
  },
};

export const WithSubtitle: Story = {
  render: () => (
    <Accordion
      title="Main title"
      subtitle="This is a subtitle for context"
      defaultOpen={true}
    >
      <ContentContainer>
        <p>Content appears here below both title and subtitle.</p>
      </ContentContainer>
    </Accordion>
  ),
  play: async ({ canvas }) => {
    await expect(canvas.getByText('Main title')).toBeVisible();
    await expect(canvas.getByText('This is a subtitle for context')).toBeVisible();
    await expect(canvas.getByText(/content appears here/i)).toBeVisible();
  },
};

export const WithToggle: Story = {
  render: () => (
    <Accordion title="Toggle me" defaultOpen={false} disableAnimations={true}>
      <ContentContainer>
        <p>Click the title to toggle this content.</p>
      </ContentContainer>
    </Accordion>
  ),
  play: async ({ canvas, userEvent }) => {
    const toggle = canvas.getByRole('button', { name: /toggle me/i });

    // Initially closed
    let content = canvas.getByText(/click the title to toggle/i);
    let accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'false');

    // Click to open
    await userEvent.click(toggle);
    accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'true');

    // Click to close
    await userEvent.click(toggle);
    accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'false');
  },
};

