import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { useState, useRef } from 'react';
import { Button } from '@leafygreen-ui/button';
import styled from '@emotion/styled';
import Popconfirm from './index';

const meta = {
  component: Popconfirm,
  title: 'Components/Popconfirm',
} satisfies Meta<typeof Popconfirm>;

export default meta;
type Story = StoryObj<typeof meta>;

const Container = styled.div`
  padding: 40px;
`;

const PopconfirmWithState = ({ defaultOpen = false }) => {
  const [open, setOpen] = useState(defaultOpen);
  const [confirmed, setConfirmed] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);

  return (
    <Container>
      <Button
        ref={buttonRef}
        onClick={() => setOpen(true)}
      >
        Delete Item
      </Button>
      <Popconfirm
        align="top"
        justify="start"
        open={open}
        refEl={buttonRef.current}
        setOpen={setOpen}
        onConfirm={() => setConfirmed(true)}
      >
        <p>Are you sure you want to delete this item?</p>
        <p>This action cannot be undone.</p>
      </Popconfirm>
      {confirmed && <p style={{ marginTop: '16px', color: 'green' }}>✓ Item deleted!</p>}
    </Container>
  );
};

export const Closed: Story = {
  render: () => <PopconfirmWithState defaultOpen={false} />,
  play: async ({ canvas }) => {
    const deleteButton = canvas.getByRole('button', { name: /delete item/i });
    await expect(deleteButton).toBeVisible();
    // Popover content should not be visible when closed
    await expect(canvas.queryByText(/are you sure/i)).not.toBeInTheDocument();
  },
};

export const Open: Story = {
  render: () => <PopconfirmWithState defaultOpen={true} />,
  play: async ({ canvas }) => {
    // Confirmation text should be visible
    await expect(canvas.getByText(/are you sure you want to delete/i)).toBeVisible();
    await expect(canvas.getByText(/this action cannot be undone/i)).toBeVisible();
    // Action buttons should be visible
    await expect(canvas.getByRole('button', { name: /cancel/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /yes/i })).toBeVisible();
  },
};

export const WithCustomText: Story = {
  render: () => {
    const [open, setOpen] = useState(false);
    const buttonRef = useRef<HTMLButtonElement>(null);

    return (
      <Container>
        <Button
          ref={buttonRef}
          onClick={() => setOpen(true)}
        >
          Confirm Action
        </Button>
        <Popconfirm
          align="top"
          justify="start"
          open={open}
          refEl={buttonRef.current}
          setOpen={setOpen}
          confirmText="Proceed"
          onConfirm={() => {}}
        >
          <p>Do you want to proceed with this action?</p>
        </Popconfirm>
      </Container>
    );
  },
  play: async ({ canvas }) => {
    const button = canvas.getByRole('button', { name: /confirm action/i });
