import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import styled from '@emotion/styled';
import Accordion from './index';

const meta = {
  component: Accordion,
  title: 'Components/Accordion',
} satisfies Meta<typeof Accordion>;

export default meta;
type Story = StoryObj<typeof meta>;

const ContentContainer = styled.div`
  padding: 16px;
  background-color: #f5f5f5;
  border-radius: 4px;
`;

export const Closed: Story = {
  render: () => (
    <Accordion title="Click to expand">
      <ContentContainer>
        <p>This is the expanded content that appears when you click the accordion header.</p>
      </ContentContainer>
    </Accordion>
  ),
  play: async ({ canvas, userEvent }) => {
    const toggle = canvas.getByRole('button', { name: /click to expand/i });
    await expect(toggle).toBeVisible();

    // Content should be hidden
    const content = canvas.getByText(/this is the expanded content/i);
    const accordion = content.closest('[data-cy="accordion-collapse-container"]');
    await expect(accordion).toHaveAttribute('aria-expanded', 'false');
  },
