    18→`;
    19→
    20→// only use for statuses whose color is not supported by leafygreen badge variants, i.e. SystemFailed, TestTimedOut, SetupFailed
    21→const StyledBadge = styled(Badge)<BadgeColorProps>`
    22→  ${({ border }) => border && `border-color: ${border} !important;`}
    23→  ${({ fill }) => fill && `background-color: ${fill} !important;`}
