    26→`;
    27→
    28→interface TaskStatusBadgeProps {
    29→  taskCount?: number;
    30→  status: TaskStatus | TaskStatusUmbrella | undefined;
    31→}
    32→const TaskStatusBadge: React.FC<TaskStatusBadgeProps> = ({
    33→  status,
    34→  taskCount,
    35→}) => {
    36→  if (!status) {
    37→    return null;
    38→  }
    39→
    40→  const statusText = taskStatusToCopy[status] ?? status;
    41→
    42→  const badgeCopy =
    43→    taskCount === undefined ? statusText : `${taskCount} ${statusText}`;
    44→  return (
    45→    <StyledBadge
    46→      key={status}
    47→      data-cy="task-status-badge"
    48→      variant={mapTaskStatusToBadgeVariant[status]}
    49→      {...customBadgeColors(status)}
    50→    >
    51→      {badgeCopy}
    52→    </StyledBadge>
    53→  );
    54→};
    55→
    56→const mapTaskStatusToBadgeVariant: Record<string, Variant> = {
    57→  [TaskStatus.Inactive]: Variant.LightGray,
    58→  [TaskStatus.Unstarted]: Variant.LightGray,
    59→  [TaskStatus.Undispatched]: Variant.LightGray,
    60→  [TaskStatus.Blocked]: Variant.LightGray,
    61→  [TaskStatus.Pending]: Variant.LightGray,
    62→  [TaskStatus.Unscheduled]: Variant.LightGray,
    63→  [TaskStatus.Aborted]: Variant.LightGray,
    64→  [TaskStatus.Started]: Variant.Yellow,
    65→  [TaskStatus.Dispatched]: Variant.Yellow,
    66→  [TaskStatus.Failed]: Variant.Red,
    67→  [TaskStatus.TestTimedOut]: Variant.Red,
    68→  [TaskStatus.TaskTimedOut]: Variant.Red,
    69→  [TaskStatus.Succeeded]: Variant.Green,
    70→  [TaskStatus.WillRun]: Variant.DarkGray,
    71→};
    72→const customBadgeColors = (status: string) => {
    73→  switch (status) {
    74→    case TaskStatus.SetupFailed:
    75→      return {
    76→        border: purple.base,
    77→        fill: purple.light2,
    78→        text: purple.dark2,
    79→      };
    80→    case TaskStatus.SystemFailed:
    81→    case TaskStatus.SystemUnresponsive:
    82→    case TaskStatus.SystemTimedOut:
    83→      return {
    84→        border: purple.dark3,
